const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

function basePremiumFor(item: ItemSpec): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

function sumBasePremiums(items: ItemSpec[]): number {
  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
}

function runeBlockAdjustment(items: ItemSpec[]): number {
  const runeCount = items.filter((item) => item.type === "rune").length;
  if (runeCount !== RUNE_BLOCK_SIZE) return 0;
  return RUNE_BLOCK_PRICE - runeCount * basePremiumFor({ type: "rune" });
}

export function quote(input: QuoteInput): QuoteResult {
  const policyBasePremium =
    sumBasePremiums(input.items) + runeBlockAdjustment(input.items);
  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
  return {
    premium: policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
  };
}
